#!/bin/bash
# =============================================================================
# Game Engine Casino - Automated Setup Script
# =============================================================================
# Usage: ./setup.sh
# No manual configuration required - everything is auto-generated
# =============================================================================

set -e

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$SCRIPT_DIR"

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m'

log() { echo -e "${GREEN}[✓]${NC} $1"; }
warn() { echo -e "${YELLOW}[!]${NC} $1"; }
error() { echo -e "${RED}[✗]${NC} $1"; }
step() { echo -e "\n${BLUE}=== $1 ===${NC}"; }

# =============================================================================
# STEP 1: Generate Environment Variables
# =============================================================================
step "Step 1: Generating environment variables"

# Auto-generate secrets
JWT_SECRET=$(openssl rand -base64 64 | tr -d '\n')
DB_PASSWORD=$(openssl rand -base64 16 | tr -d '\n/+')
REDIS_PASSWORD=$(openssl rand -base64 16 | tr -d '\n/+')
WS_SECRET=$(openssl rand -base64 64 | tr -d '\n')
ENCRYPTION_KEY=$(openssl rand -base32 32 | tr -d '=')
ADMIN_PASSWORD=$(openssl rand -base64 12 | tr -d '\n/+')

# Get server IP
SERVER_IP=$(hostname -I | awk '{print $1}')
[ -z "$SERVER_IP" ] && SERVER_IP="127.0.0.1"

# Generate RSA keys for JWT (RS256)
if [ ! -f certs/jwt-private.pem ] || [ ! -f certs/jwt-public.pem ]; then
    mkdir -p certs
    openssl genrsa -out certs/jwt-private.pem 4096 2>/dev/null
    openssl rsa -in certs/jwt-private.pem -pubout -out certs/jwt-public.pem 2>/dev/null
    log "Generated RSA JWT keys (RS256)"
fi

log "Generated all secrets (JWT, DB, Redis, WS)"

# =============================================================================
# STEP 2: Create .env file
# =============================================================================
step "Step 2: Creating .env file"

cat > .env << EOF
# ===========================================
