# Server: ${SERVER_IP}
# Generated: $(date)
# ===========================================

# General
ENVIRONMENT=production
LOG_LEVEL=info
SERVER_IP=${SERVER_IP}

# PostgreSQL
POSTGRES_USER=postgres
