chmod 600 .env
log "Created .env with auto-generated secrets"

# =============================================================================
# STEP 3: Install Dependencies
# =============================================================================
step "Step 3: Checking dependencies"

check_cmd() {
    if command -v "$1" &>/dev/null; then
        log "$1 found: $(command -v $1)"
    else
        error "$1 not found"
        MISSING_DEPS=1
    fi
}

MISSING_DEPS=0
check_cmd docker
check_cmd docker-compose

if [ "$MISSING_DEPS" = "1" ]; then
    warn "Installing missing dependencies..."
    
    # Install Docker
    if ! command -v docker &>/dev/null; then
        curl -fsSL https://get.docker.com | sh
        sudo usermod -aG docker $USER
        sudo systemctl enable docker
        sudo systemctl start docker
        log "Docker installed"
    fi
    
    # Install Docker Compose
    if ! command -v docker-compose &>/dev/null; then
        sudo curl -L "https://github.com/docker/compose/releases/latest/download/docker-compose-$(uname -s)-$(uname -m)" -o /usr/local/bin/docker-compose
        sudo chmod +x /usr/local/bin/docker-compose
        log "Docker Compose installed"
    fi
fi

# =============================================================================
# STEP 4: Build All Docker Images
# =============================================================================
step "Step 4: Building Docker images (this may take 5-10 minutes)"

export $(cat .env | grep -v '^#' | xargs)

# Build Go services
GO_SERVICES="auth-service user-service wallet-service game-registry card-games dice-games slot-games rng-service betting tournament jackpot-service leaderboard-service winners-showcase-service merchant-service agent-service loyalty-service live-dealer-service sports-betting-service game-engine multiplayer chat notification banner-service referral-service"

for svc in $GO_SERVICES; do
    if [ -f "services/$svc/Dockerfile" ]; then
        echo -n "  Building $svc..."
        docker build -t game-engine/$svc:latest services/$svc/ -q 2>/dev/null && echo " ✓" || echo " ✗"
    else
        echo "  ⚠ $svc - no Dockerfile found"
    fi
done

# Build gateways
echo -n "  Building gateway-player..."
docker build -t game-engine/gateway-player:latest services/gateway/ -f services/gateway/Dockerfile.player -q 2>/dev/null && echo " ✓" || echo " ✗"

echo -n "  Building gateway-admin..."
docker build -t game-engine/gateway-admin:latest services/gateway/admin/ -q 2>/dev/null && echo " ✓" || echo " ✗"

echo -n "  Building gateway-merchant..."
docker build -t game-engine/gateway-merchant:latest services/gateway/merchant/ -q 2>/dev/null && echo " ✓" || echo " ✗"

echo -n "  Building gateway-agent..."
docker build -t game-engine/gateway-agent:latest services/gateway/agent/ -q 2>/dev/null && echo " ✓" || echo " ✗"

# Build Java services
JAVA_SERVICES="payment-service bonus-service commission-service affiliate-service"
for svc in $JAVA_SERVICES; do
    if [ -f "services/$svc/Dockerfile" ]; then
        echo -n "  Building $svc..."
        docker build -t game-engine/$svc:latest services/$svc/ -q 2>/dev/null && echo " ✓" || echo " ✗"
    fi
done

# Build Python services
PYTHON_SERVICES="kyc-service aml-service fraud-service risk-service"
for svc in $PYTHON_SERVICES; do
    if [ -f "services/$svc/Dockerfile" ]; then
        echo -n "  Building $svc..."
        docker build -t game-engine/$svc:latest services/$svc/ -q 2>/dev/null && echo " ✓" || echo " ✗"
    fi
done

# Build WebSocket gateway
echo -n "  Building websocket-gateway..."
docker build -t game-engine/websocket-gateway:latest services/websocket-gateway/ -q 2>/dev/null && echo " ✓" || echo " ✗"

# Build admin panel
echo -n "  Building admin-panel..."
docker build -t game-engine/admin-panel:latest admin/ -q 2>/dev/null && echo " ✓" || echo " ✗"

log "All Docker images built"

# =============================================================================
# STEP 5: Start Infrastructure
# =============================================================================
step "Step 5: Starting infrastructure (PostgreSQL, Redis, NATS)"

# Create volumes
docker volume create game-engine-postgres-data 2>/dev/null
docker volume create game-engine-redis-data 2>/dev/null
docker volume create game-engine-nats-data 2>/dev/null

# Start infrastructure
docker compose -f docker-compose.dev.yml up -d

# Wait for PostgreSQL
echo -n "  Waiting for PostgreSQL..."
for i in $(seq 1 60); do
    if docker exec game_engine-postgres pg_isready -U postgres &>/dev/null; then
        echo " ✓"
        break
    fi
    echo -n "."
    sleep 2
done

# Wait for Redis
echo -n "  Waiting for Redis..."
for i in $(seq 1 30); do
    if docker exec game_engine-redis redis-cli ping &>/dev/null; then
        echo " ✓"
        break
    fi
    echo -n "."
    sleep 1
done

# Wait for NATS
echo -n "  Waiting for NATS..."
for i in $(seq 1 30); do
    if curl -s http://localhost:8222/healthz &>/dev/null; then
        echo " ✓"
        break
    fi
    echo -n "."
    sleep 1
done

log "Infrastructure ready"

# =============================================================================
# STEP 6: Start Application Services
# =============================================================================
step "Step 6: Starting application services"

# Remove old volumes reference if exists
sed -i '/volumes:/,$ d' docker-compose.yml 2>/dev/null

docker compose -f docker-compose.yml up -d

# Wait for services
echo -n "  Waiting for services to start..."
sleep 15
echo " ✓"

log "All services started"

# =============================================================================
# STEP 7: Verify Deployment
# =============================================================================
step "Step 7: Verifying deployment"

check_service() {
    local name=$1
    local port=$2
    if curl -s http://localhost:$port/health &>/dev/null || \
       curl -s http://localhost:$port &>/dev/null || \
       docker ps --filter "name=$name" --filter "status=running" -q | grep -q .; then
        log "$name (port $port)"
    else
        warn "$name (port $port) - not responding yet"
    fi
}

check_service "postgres" 5432
check_service "redis" 6379
check_service "nats" 4222
check_service "gateway-player" 8080
check_service "gateway-admin" 8081
check_service "gateway-merchant" 8082
check_service "gateway-agent" 8083
check_service "websocket-gateway" 4000
check_service "admin-panel" 3000

# Count running containers
RUNNING=$(docker ps --filter "name=game_engine" -q | wc -l)
TOTAL=$(docker ps -a --filter "name=game_engine" -q | wc -l)
log "Containers running: $RUNNING / $TOTAL"

# =============================================================================
# STEP 8: Save Credentials
# =============================================================================
step "Step 8: Saving credentials"

cat > credentials.txt << EOF
===========================================
Game Engine Casino - Auto-Generated Credentials
Generated: $(date)
===========================================

Admin Panel:
  URL: http://${SERVER_IP}:${ADMIN_PANEL_PORT:-3000}
  Username: admin
  Password: ${ADMIN_PASSWORD}

Player API:
  URL: http://${SERVER_IP}:${GATEWAY_PLAYER_PORT:-8080}

Admin API:
  URL: http://${SERVER_IP}:${GATEWAY_ADMIN_PORT:-8081}

WebSocket:
  URL: ws://${SERVER_IP}:${WS_PORT:-4000}

Database:
  Host: ${SERVER_IP}
  Port: 5432
  User: postgres
  Password: ${DB_PASSWORD}

Redis:
  Host: ${SERVER_IP}
  Port: 6379
  Password: ${REDIS_PASSWORD}

NATS:
  URL: nats://${SERVER_IP}:4222

JWT Secret: ${JWT_SECRET}

===========================================
IMPORTANT: Keep this file secure!
===========================================
EOF

chmod 600 credentials.txt
log "Credentials saved to credentials.txt"

# =============================================================================
# COMPLETE
# =============================================================================
echo ""
echo -e "${GREEN}============================================${NC}"
echo -e "${GREEN}  Game Engine Casino - Setup Complete!${NC}"
echo -e "${GREEN}============================================${NC}"
echo ""
echo "  Admin Panel:  http://${SERVER_IP}:${ADMIN_PANEL_PORT:-3000}"
echo "  Player API:   http://${SERVER_IP}:${GATEWAY_PLAYER_PORT:-8080}"
echo "  Admin API:    http://${SERVER_IP}:${GATEWAY_ADMIN_PORT:-8081}"
echo "  WebSocket:    ws://${SERVER_IP}:${WS_PORT:-4000}"
echo ""
echo "  Admin Login:  admin / ${ADMIN_PASSWORD}"
echo ""
echo "  Credentials:  ./credentials.txt"
echo "  Logs:         docker compose -f docker-compose.yml logs -f"
echo "  Stop:         docker compose -f docker-compose.yml down"
echo ""
